import{_ as s,o as t,c as a,ak as i}from"./chunks/framework.Dga8WbZz.js";const k=JSON.parse('{"title":"Testing Strategy","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/testing-strategy.md","filePath":"advanced/testing-strategy.md"}'),r={name:"advanced/testing-strategy.md"};function n(o,e,d,l,c,h){return t(),a("div",null,[...e[0]||(e[0]=[i(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ExpressiveSharp/advanced/testing-strategy.md for this page in Markdown format</div><h1 id="testing-strategy" tabindex="-1">Testing Strategy <a class="header-anchor" href="#testing-strategy" aria-label="Permalink to “Testing Strategy”">​</a></h1><p>This document defines the testing strategy for ExpressiveSharp, covering snapshot tests, functional tests, integration test architecture, and performance benchmarks.</p><h2 id="design-principle-emit-the-closest-expression-node" tabindex="-1">Design Principle: Emit the Closest Expression Node <a class="header-anchor" href="#design-principle-emit-the-closest-expression-node" aria-label="Permalink to “Design Principle: Emit the Closest Expression Node”">​</a></h2><p>The emitter maps each <code>IOperation</code> to the most direct <code>System.Linq.Expressions</code> equivalent. For example, <code>IForEachLoopOperation</code> emits <code>Expression.Loop()</code> with the enumerator pattern -- not a direct LINQ rewrite. Transformers (like <code>ConvertLoopsToLinq</code>) handle the conversion to LINQ for providers that cannot translate <code>LoopExpression</code>.</p><p>This means:</p><ul><li>The <strong>emitter</strong> targets the full <code>System.Linq.Expressions</code> API surface</li><li><strong>Transformers</strong> adapt expression trees for specific providers (EF Core, etc.)</li><li>The <strong>ExpressionCompile runner</strong> validates all expression types (compiles and executes in-process)</li><li>The <strong>EntityFrameworkCore runner</strong> validates the EF Core-translatable subset</li></ul><h2 id="three-verification-levels" tabindex="-1">Three Verification Levels <a class="header-anchor" href="#three-verification-levels" aria-label="Permalink to “Three Verification Levels”">​</a></h2><h3 id="level-1-compilation-does-the-generated-code-compile" tabindex="-1">Level 1: Compilation -- Does the generated code compile? <a class="header-anchor" href="#level-1-compilation-does-the-generated-code-compile" aria-label="Permalink to “Level 1: Compilation -- Does the generated code compile?”">​</a></h3><p>The source generator produces C# code that builds an <code>Expression&lt;TDelegate&gt;</code> using factory methods. This generated code must compile without errors.</p><p><strong>Test mechanism:</strong> <code>GeneratorTestBase.RunExpressiveGenerator()</code> compiles the generated output via Roslyn and asserts zero diagnostics.</p><h3 id="level-2-diagnostics-does-it-compile-without-warnings" tabindex="-1">Level 2: Diagnostics -- Does it compile without warnings? <a class="header-anchor" href="#level-2-diagnostics-does-it-compile-without-warnings" aria-label="Permalink to “Level 2: Diagnostics -- Does it compile without warnings?”">​</a></h3><p><code>TreatWarningsAsErrors</code> is enabled project-wide. The generator reports diagnostics (EXP0001 through EXP0012) for unsupported constructs, and these are verified by tests.</p><h3 id="level-3-behavioral-does-the-expression-tree-produce-correct-results" tabindex="-1">Level 3: Behavioral -- Does the expression tree produce correct results? <a class="header-anchor" href="#level-3-behavioral-does-the-expression-tree-produce-correct-results" aria-label="Permalink to “Level 3: Behavioral -- Does the expression tree produce correct results?”">​</a></h3><p>The generated expression tree must be functionally equivalent to the original method body. Integration tests seed canonical data, execute queries via expanded expression trees, and assert results match expected values.</p><h2 id="test-projects" tabindex="-1">Test Projects <a class="header-anchor" href="#test-projects" aria-label="Permalink to “Test Projects”">​</a></h2><table tabindex="0"><thead><tr><th>Project</th><th>Purpose</th><th>Level</th></tr></thead><tbody><tr><td><code>ExpressiveSharp.Generator.Tests</code></td><td>Snapshot tests (Verify.MSTest) -- validates generated C# output</td><td>1, 2</td></tr><tr><td><code>ExpressiveSharp.Tests</code></td><td>Unit tests for runtime services, transformers, extensions</td><td>3</td></tr><tr><td><code>ExpressiveSharp.IntegrationTests</code></td><td>In-memory compiled-delegate tests (ExpressionCompile path). Also hosts the shared Store scenario models (<code>Order</code>, <code>Customer</code>, <code>LineItem</code>, <code>Address</code>) and seed data used by both test projects.</td><td>3</td></tr><tr><td><code>ExpressiveSharp.EntityFrameworkCore.IntegrationTests</code></td><td>All EF Core integration tests (scenarios, async queryables, window functions, ExecuteUpdate, Include, query filters, conventions). Default: SQLite. Containers: SqlServer/Postgres/PomeloMySql/Cosmos via <code>-p:TestDatabase=&lt;provider&gt;</code></td><td>3</td></tr></tbody></table><h2 id="integration-test-architecture" tabindex="-1">Integration Test Architecture <a class="header-anchor" href="#integration-test-architecture" aria-label="Permalink to “Integration Test Architecture”">​</a></h2><p>Two test projects, one feature set per backend — no runner abstraction:</p><h3 id="expressioncompile-in-memory" tabindex="-1">ExpressionCompile (in-memory) <a class="header-anchor" href="#expressioncompile-in-memory" aria-label="Permalink to “ExpressionCompile (in-memory)”">​</a></h3><p><strong><code>ExpressiveSharp.IntegrationTests</code></strong> -- Contains the shared Store scenario models / seed data plus <code>[TestClass]</code> test classes (<code>CommonScenarioTests</code>, <code>StoreQueryTests</code>, <code>AnonymousTypeInterceptorTests</code>, <code>MultiLambdaInterceptorTests</code>). Each test compiles an expanded expression tree to a delegate via <code>.Compile()</code> and runs it against seeded <code>List&lt;T&gt;</code> collections through the internal <code>ExpressionCompileRunner</code> helper. Validates all expression types including <code>LoopExpression</code>.</p><h3 id="entityframeworkcore" tabindex="-1">EntityFrameworkCore <a class="header-anchor" href="#entityframeworkcore" aria-label="Permalink to “EntityFrameworkCore”">​</a></h3><p><strong><code>ExpressiveSharp.EntityFrameworkCore.IntegrationTests</code></strong> -- Two-level test base hierarchy:</p><ul><li><strong><code>EFCoreTestBase</code></strong> — base lifecycle (context create / <code>EnsureCreated</code> / per-test database drop). Derived test bases that work on any EF Core provider (including Cosmos) extend this. <code>Context</code> is typed as <code>DbContext</code> so tests use <code>Context.Set&lt;T&gt;()</code>.</li><li><strong><code>EFCoreRelationalTestBase : EFCoreTestBase</code></strong> — adds a strongly-typed <code>IntegrationTestDbContext Context</code> shadow. Derived test bases that require relational features (window functions, <code>ExecuteUpdate</code>, typed DbSet access) extend this; Cosmos concrete classes never do.</li></ul><p>Feature test bases:</p><ul><li>Extend <code>EFCoreTestBase</code>: <code>CommonScenarioTestBase</code>, <code>StoreQueryTestBase</code> (run on Cosmos + all relational providers)</li><li>Extend <code>EFCoreRelationalTestBase</code>: <code>WindowFunctionTestBase</code>, <code>ExecuteUpdateTestBase</code>, <code>AsyncQueryableTestBase</code>, <code>CapturedVariableTestBase</code>, <code>IncludeTestBase</code>, <code>UseExpressivesConventionTestBase</code>, <code>ExpressiveExpansionTestBase</code></li><li>Standalone (own DbContext): <code>QueryFilterTestBase</code></li></ul><p>Per-provider concrete classes live under <code>Tests/&lt;Provider&gt;/</code> and implement <code>CreateContextHandle</code> using <code>TestContextFactories.Create&lt;Provider&gt;()</code>. Default <code>dotnet test</code> runs SQLite only; <code>-p:TestDatabase=&lt;provider&gt;</code> enables container-backed testing (see <code>.test-containers.sh</code>).</p><h2 id="adding-tests-for-a-new-ioperation-mapping" tabindex="-1">Adding Tests for a New IOperation Mapping <a class="header-anchor" href="#adding-tests-for-a-new-ioperation-mapping" aria-label="Permalink to “Adding Tests for a New IOperation Mapping”">​</a></h2><p>When implementing a new <code>EmitOperation</code> case:</p><ol><li><p><strong>Snapshot test</strong> -- Add a test in <code>ExpressiveSharp.Generator.Tests</code> that feeds source code through the generator and verifies the output compiles and matches a snapshot.</p></li><li><p><strong>Integration test</strong> -- Add an <code>[Expressive]</code> member to the Store model or use <code>ExpressionPolyfill.Create(...)</code>, then add assertions in an abstract test class. Both ExpressionCompile and EntityFrameworkCore runners pick it up automatically.</p></li><li><p><strong>Transformer unit test</strong> -- If the feature requires a transformer for LINQ provider compatibility, add tests in <code>ExpressiveSharp.Tests/Transformers/</code> that build expression trees manually and verify the transformer rewrites them correctly.</p></li></ol><h2 id="snapshot-tests" tabindex="-1">Snapshot Tests <a class="header-anchor" href="#snapshot-tests" aria-label="Permalink to “Snapshot Tests”">​</a></h2><p>Snapshot tests use <a href="https://github.com/VerifyTests/Verify" target="_blank" rel="noreferrer">Verify.MSTest</a> to compare generated C# output against committed <code>*.verified.cs</code> files.</p><div class="tip custom-block"><p class="custom-block-title">Accepting New Snapshots</p><p>When generated output changes (new feature, bugfix, etc.), accept the new baselines:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VERIFY_AUTO_APPROVE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/ExpressiveSharp.Generator.Tests</span></span></code></pre></div><p>Review the diff in <code>*.verified.cs</code> files before committing.</p></div><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>The <code>*.verified.cs</code> files alongside tests in <code>tests/ExpressiveSharp.Generator.Tests/</code> are the expected output. Always commit them with your changes.</p></div><h2 id="running-tests" tabindex="-1">Running Tests <a class="header-anchor" href="#running-tests" aria-label="Permalink to “Running Tests”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># All tests</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Single project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/ExpressiveSharp.Generator.Tests</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Single test by name</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;FullyQualifiedName~MyTestName&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run against a specific target framework</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net8.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Release</span></span></code></pre></div><p>CI targets both .NET 8.0 and .NET 10.0 SDKs.</p><h2 id="performance-benchmarks" tabindex="-1">Performance Benchmarks <a class="header-anchor" href="#performance-benchmarks" aria-label="Permalink to “Performance Benchmarks”">​</a></h2><p>Beyond correctness testing, the project includes BenchmarkDotNet benchmarks in <code>benchmarks/ExpressiveSharp.Benchmarks/</code> that track performance across key hot paths.</p><table tabindex="0"><thead><tr><th>Benchmark class</th><th>What it measures</th></tr></thead><tbody><tr><td><code>GeneratorBenchmarks</code></td><td>Cold and incremental <code>ExpressiveGenerator</code> runs (parameterized by member count)</td></tr><tr><td><code>PolyfillGeneratorBenchmarks</code></td><td>Cold and incremental <code>PolyfillInterceptorGenerator</code> runs</td></tr><tr><td><code>ExpressionResolverBenchmarks</code></td><td>Registry vs. reflection lookup for properties, methods, constructors</td></tr><tr><td><code>ExpressionReplacerBenchmarks</code></td><td><code>ExpressiveReplacer.Replace</code> on various expression tree shapes</td></tr><tr><td><code>TransformerBenchmarks</code></td><td>Each transformer in isolation + full <code>ExpandExpressives</code> pipeline</td></tr><tr><td><code>EFCoreQueryOverheadBenchmarks</code></td><td>End-to-end EF Core <code>ToQueryString()</code> overhead + cold-start cost</td></tr></tbody></table><h3 id="ci-regression-detection" tabindex="-1">CI Regression Detection <a class="header-anchor" href="#ci-regression-detection" aria-label="Permalink to “CI Regression Detection”">​</a></h3><p>A separate GitHub Actions workflow (<code>.github/workflows/benchmarks.yml</code>) runs benchmarks on every push to <code>main</code> and on pull requests. Results are stored on the <code>gh-pages</code> branch and compared against the last <code>main</code> baseline using <code>benchmark-action/github-action-benchmark</code>. PRs that regress beyond 20% receive an automated comment.</p><h3 id="running-benchmarks-locally" tabindex="-1">Running Benchmarks Locally <a class="header-anchor" href="#running-benchmarks-locally" aria-label="Permalink to “Running Benchmarks Locally”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run all benchmarks (full BenchmarkDotNet defaults)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Release</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/ExpressiveSharp.Benchmarks/ExpressiveSharp.Benchmarks.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run a specific class</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Release</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/ExpressiveSharp.Benchmarks/ExpressiveSharp.Benchmarks.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*GeneratorBenchmarks*&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Quick run (CI-style, fewer iterations)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Release</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> benchmarks/ExpressiveSharp.Benchmarks/ExpressiveSharp.Benchmarks.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --filter</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --job</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> short</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --iterationCount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --warmupCount</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><h3 id="benchmark-dashboard" tabindex="-1">Benchmark Dashboard <a class="header-anchor" href="#benchmark-dashboard" aria-label="Permalink to “Benchmark Dashboard”">​</a></h3><p>The benchmark results are published to an interactive dashboard at <a href="https://efnext.github.io/ExpressiveSharp/dev/bench/" target="_blank" rel="noreferrer"><code>/dev/bench/</code></a>. The dashboard tracks the following metrics over time:</p><ul><li><strong>Generator cold start</strong> -- Time for the <code>ExpressiveGenerator</code> to process a compilation from scratch</li><li><strong>Generator incremental</strong> -- Time for an incremental re-run after a non-semantic edit</li><li><strong>Resolver lookup</strong> -- Time for <code>ExpressiveResolver.FindGeneratedExpression</code> via registry and reflection paths</li><li><strong>Replacer traversal</strong> -- Time for <code>ExpressiveReplacer</code> to walk and replace expression trees of varying complexity</li><li><strong>Transformer pipeline</strong> -- Per-transformer and end-to-end pipeline throughput</li><li><strong>EF Core overhead</strong> -- The delta between a vanilla EF Core query and one with <code>UseExpressives()</code> expansion</li></ul><p>Use the dashboard to identify regressions before they reach production and to evaluate the performance impact of new features.</p>`,48)])])}const g=s(r,[["render",n]]);export{k as __pageData,g as default};
